function solve(nums) {
    const n = nums.length;
    const sortedNums = [...nums].sort((a, b) => a - b);
    let totalSum = 0;

    // Helper function to check if a subarray can be sorted by cyclic shifts
    // A subarray can be sorted by cyclic shifts if and only if the elements
    // in the subarray are a permutation of the elements in the target sorted segment
    // and they can be rearranged into the target segment via cyclic shifts.
    // For a block of size k, it can be sorted if and only if the multiset of elements
    // in the block matches the multiset of elements in the corresponding segment of the fully sorted array.
    const canSortBlock = (arr, start, k, sortedArr) => {
        // The elements in arr[start...start+k-1] must be exactly the elements
        // in sortedArr[start...start+k-1] (as multisets).
        const block = arr.slice(start, start + k);
        const target = sortedArr.slice(start, start + k);

        // Simple check: check if the sorted block matches the target segment.
        // If they are permutations of each other, they can be cyclically shifted
        // into any permutation *within that block* if k > 1, provided the elements are distinct.
        // However, the constraint here is stronger: they must form the *exact* target segment after shifting.

        // If k=1, it's always sorted (trivially).
        if (k === 1) return true;

        // The core idea: if a block of size k can be cyclically shifted to match the target sorted segment,
        // it means the elements in the block *must* be the same as the elements in the target segment,
        // AND there must exist a shift 's' (0 <= s < k) such that:
        // arr[(start + i) % k] === sortedArr[start + (i + s) % k] for all i in [0, k-1].
        // Wait, the problem says: "independently for each subarray... perform cyclic shifts".
        // A block B = [b_0, b_1, ..., b_{k-1}] can be transformed into any of its k cyclic rotations.
        // Let the target segment be T = [t_0, t_1, ..., t_{k-1}] (which is sorted).
        // B can be transformed into T if T is a cyclic rotation of B.

        // Check if T is a cyclic rotation of B.
        // Concatenate B with itself: B' = [b_0, ..., b_{k-1}, b_0, ..., b_{k-1}]
        // T must be a contiguous subarray of length k within B'.

        const bString = block.join(',');
        const tString = target.join(',');
        const bDouble = bString + ',' + bString.slice(1); // Simplified conceptual concatenation for string matching, safer to use arrays/indices

        // A more robust check for cyclic rotation:
        // 1. Check if they are permutations (necessary condition).
        const sortedBlock = [...block].sort((a, b) => a - b);
        const sortedTarget = [...target].sort((a, b) => a - b);
        if (sortedBlock.join(',') !== sortedTarget.join(',')) {
            return false; // Not a permutation of each other
        }

        // 2. Check if T is a cyclic rotation of B.
        // T is a cyclic rotation of B if T matches B shifted by some amount 's'.
        for (let s = 0; s < k; s++) {
            let match = true;
            for (let i = 0; i < k; i++) {
                // T[i] must equal B[(i + s) % k] if we consider T being B shifted right by s positions,
                // or T[i] must equal B[(i - s + k) % k] if we consider T being B shifted left by s positions.
                // Let's stick to the definition: T is a rotation of B.
                // If B = [b_0, ..., b_{k-1}], a right shift by s results in [b_{k-s}, ..., b_{k-1}, b_0, ..., b_{k-s-1}]
                // A left shift by s results in [b_s, ..., b_{k-1}, b_0, ..., b_{s-1}]

                // We need to check if T[i] == B[(i + s) % k] for *some* s.
                // Wait, the operation is "left or right shift". Any rotation is achievable.
                // T is a rotation of B iff T is a contiguous substring of B + B.

                // Check if T matches B shifted left by 's':
                // T[i] should match B[(i + s) % k] if we think of 's' as the amount B is shifted *left* to get T.
                // If T[0] = B[s], T[1] = B[s+1], ..., T[k-1] = B[s+k-1] (indices mod k).
                const expectedIndexInB = (i + s) % k;
                if (target[i] !== block[expectedIndexInB]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }

        return false;
    };

    // Find all divisors of n
    const divisors = [];
    for (let i = 1; i * i <= n; i++) {
        if (n % i === 0) {
            divisors.push(i);
            if (i * i !== n) {
                divisors.push(n / i);
            }
        }
    }

    for (const k of divisors) {
        let isSortable = true;

        if (k === 1) {
            // If k=1, each block has one element. It cannot be reordered unless the array is already sorted.
            // For k=1, the operation is trivial. The array remains unchanged.
            if (nums.join(',') !== sortedNums.join(',')) {
                isSortable = false;
            } else {
                // If already sorted, k=1 is sortable.
            }
        } else {
            // Check all contiguous blocks of size k
            const numBlocks = n / k;
            for (let j = 0; j < numBlocks; j++) {
                const start = j * k;

                // The block is nums[start...start+k-1]
                // The target segment is sortedNums[start...start+k-1]

                if (!canSortBlock(nums, start, k, sortedNums)) {
                    isSortable = false;
                    break;
                }
            }
        }

        if (isSortable) {
            totalSum += k;
        }
    }

    return totalSum;
}

