import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class Solution {
    /**
     * Checks if the target segment is a cyclic rotation of the block.
     * Target is sortedNums[start...start+k-1].
     * Block is nums[start...start+k-1].
     *
     * @param nums The original array.
     * @param start The starting index of the block/segment.
     * @param k The size of the block.
     * @param sortedNums The fully sorted version of nums.
     * @return true if the block can be cyclically shifted to match the target segment, false otherwise.
     */
    private static boolean canSortBlock(long[] nums, int start, int k, long[] sortedNums) {
        if (k == 1) {
            // Trivial case: one element block always matches itself if elements are the same.
            // Since they come from the same original array, they are the same element.
            return true;
        }

        // 1. Permutation check (Necessary condition)
        long[] block = new long[k];
        long[] target = new long[k];
        for (int i = 0; i < k; i++) {
            block[i] = nums[start + i];
            target[i] = sortedNums[start + i];
        }

        long[] sortedBlock = Arrays.copyOf(block, k);
        Arrays.sort(sortedBlock);

        long[] sortedTarget = Arrays.copyOf(target, k);
        Arrays.sort(sortedTarget);

        if (!Arrays.equals(sortedBlock, sortedTarget)) {
            return false; // Not a permutation of each other
        }

        // 2. Cyclic Rotation check (Sufficient condition)
        // Target T is a cyclic rotation of Block B if T is a contiguous subarray of B + B.

        // We check if T matches B shifted left by 's' for any s in [0, k-1].
        // Left shift by s: B[s], B[s+1], ..., B[k-1], B[0], ..., B[s-1]
        for (int s = 0; s < k; s++) {
            boolean match = true;
            for (int i = 0; i < k; i++) {
                // The element at T[i] must correspond to B[(i + s) % k] in a left shift interpretation,
                // OR, more simply: T[i] must match B[j] where j is the index in B that maps to T[i] after some shift.
                // If T is B shifted left by s, then T[i] = B[(i + s) % k] is WRONG.
                // If B is shifted left by s, the new element at index i was originally at index (i + s) % k.
                // Let's use the standard definition: T is a rotation of B if T[i] == B[(i + s) % k] for some s.

                // If we left shift B by 's' positions, the element originally at index 'j' moves to index (j-s+k)%k.
                // We want T[i] == B[j]. So, i = (j-s+k)%k.
                // This is getting complicated. Let's stick to the easiest check: T is a substring of B+B.

                // We check if T matches B shifted left by 's':
                // T[0] == B[s]
                // T[1] == B[(s+1)%k]
                // ...
                // T[i] == B[(s+i)%k]
                int expectedIndexInB = (s + i) % k;
                if (target[i] != block[expectedIndexInB]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }

        return false;
    }


    public static long solve(long[] nums) {
        int n = nums.length;
        long[] sortedNums = Arrays.copyOf(nums, n);
        Arrays.sort(sortedNums);

        long totalSum = 0;

        // Find all divisors of n
        List<Integer> divisors = new ArrayList<>();
        for (int i = 1; i * i <= n; i++) {
            if (n % i == 0) {
                divisors.add(i);
                if (i * i != n) {
                    divisors.add(n / i);
                }
            }
        }

        for (int k : divisors) {
            boolean isSortable = true;

            if (k == 1) {
                // If k=1, the array remains unchanged by operation. It is sortable iff it is already sorted.
                if (!Arrays.equals(nums, sortedNums)) {
                    isSortable = false;
                }
            } else {
                // Check all contiguous blocks of size k
                int numBlocks = n / k;
                for (int j = 0; j < numBlocks; j++) {
                    int start = j * k;

                    // Check if the block nums[start...start+k-1] can be cyclically shifted to match sortedNums[start...start+k-1]
                    if (!canSortBlock(nums, start, k, sortedNums)) {
                        isSortable = false;
                        break;
                    }
                }
            }

            if (isSortable) {
                totalSum += k;
            }
        }

        return totalSum;
    }
}
