class Solution {
    /**
     * Checks if a block of size k starting at 'start' in 'nums' can be cyclically shifted
     * to match the corresponding segment in 'sortedNums'.
     * 
     * @param nums The original array.
     * @param sortedNums The target sorted array.
     * @param start The starting index of the block (must be a multiple of k).
     * @param k The size of the block.
     * @return true if the block can be transformed into the target segment via cyclic shifts, false otherwise.
     */
    private boolean canSortBlock(long[] nums, long[] sortedNums, int start, int k) {
        // Extract the block B from nums
        long[] block = new long[k];
        for (int i = 0; i < k; i++) {
            block[i] = nums[start + i];
        }

        // Extract the target segment T from sortedNums
        long[] target = new long[k];
        for (int i = 0; i < k; i++) {
            target[i] = sortedNums[start + i];
        }

        if (k == 1) {
            return true; // Trivial case
        }

        // Necessary condition: B and T must be permutations of each other.
        long[] sortedBlock = Arrays.copyOf(block, k);
        Arrays.sort(sortedBlock);
        long[] sortedTarget = Arrays.copyOf(target, k);
        Arrays.sort(sortedTarget);

        if (!Arrays.equals(sortedBlock, sortedTarget)) {
            return false; // Not a permutation
        }

        // Sufficient condition: T must be a cyclic rotation of B.
        // Check if T matches B shifted left by 's' for any s in [0, k-1].
        for (int s = 0; s < k; s++) {
            boolean match = true;
            for (int i = 0; i < k; i++) {
                // Check if target[i] equals block shifted left by s.
                // T[i] should match B[(i + s) % k] where s is the amount of left shift applied to B to get T.
                // If B=[b0, b1, b2] and s=1 (left shift by 1), T=[b1, b2, b0].
