import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

class Solution {
    /**
     * Checks if the target array segment T is a cyclic rotation of the source array segment B.
     * T must be achievable from B by cyclic shifts.
     * @param B The source block.
     * @param T The target sorted segment.
     * @param k The size of the blocks.
     * @return True if T is a cyclic rotation of B, false otherwise.
     */
    private static boolean isCyclicRotation(long[] B, long[] T, int k) {
        if (k == 0) return true;
        if (k == 1) return B[0] == T[0];

        // 1. Necessary condition: they must be permutations of each other.
        long[] sortedB = Arrays.copyOf(B, k);
        long[] sortedT = Arrays.copyOf(T, k);
        Arrays.sort(sortedB);
        Arrays.sort(sortedT);
        if (!Arrays.equals(sortedB, sortedT)) {
            return false;
        }

        // 2. Check if T is a contiguous substring of B concatenated with itself (B+B).
        // We check all k possible shifts. A shift 's' means T[i] should match B[(i + s) % k] 
        // if we align T[0] with B[s].
        for (int s = 0; s < k; s++) {
            boolean match = true;
            for (int i = 0; i < k; i++) {
                // Check if T[i] matches B shifted by 's' (where 's' is the index in B that maps to T[0])
                // If T is a rotation of B, then T[i] must equal B[(i + s) % k] for some fixed s.
                // Example: B=[3,1,2], T=[1,2,3]. 
                // s=1: T[0]=1, B[(0+1)%3]=B[1]=1. T[1]=2, B[2]=2. T[2]=3, B[0]=3. Match!
                int expectedIndexInB = (i + s) % k;
                if (T[i] != B[expectedIndexInB]) {
                    match = false;
                    break;
                }
            }
            if (match) {
                return true;
            }
        }

        return false;
    }

    public static long solve(long[] nums) {
        int n = nums.length;

        // Calculate the fully sorted array
        long[] sortedNums = Arrays.copyOf(nums, n);
        Arrays.sort(sortedNums);

        long totalSum = 0;

        // Find all divisors of n
        List<Integer> divisors = new ArrayList<>();
        for (int i = 1; i * i <= n; i++) {
            if (n % i == 0) {
                divisors.add(i);
                if (i * i != n) {
                    divisors.add(n / i);
                }
            }
        }

        for (int k : divisors) {
            boolean isSortable = true;

            if (k == 1) {
                // If k=1, the array must already be sorted for it to be sortable (as no reordering is possible).
                if (!Arrays.equals(nums, sortedNums)) {
                    isSortable = false;
                }
            } else {
                // Check all contiguous blocks of size k
                int numBlocks = n / k;
                for (int j = 0; j < numBlocks; j++) {
                    int start = j * k;

                    // Extract block B (from nums)
                    long[] blockB = new long[k];
                    for (int i = 0; i < k; i++) {
                        blockB[i] = nums[start + i];
