class Solution {
    /**
     * Checks if a target array T is a cyclic rotation of an array B.
     * T must have the same length as B.
     */
    private static boolean isCyclicRotation(long[] B, long[] T) {
        int k = B.length;
        if (k == 0) return true;

        // Optimization: Check if they are permutations first (necessary condition)
        long[] sortedB = Arrays.copyOf(B, k);
        long[] sortedT = Arrays.copyOf(T, k);
        Arrays.sort(sortedB);
        Arrays.sort(sortedT);
        if (!Arrays.equals(sortedB, sortedT)) {
            return false;
        }

        // Check if T is a cyclic rotation of B
        // T is a rotation of B iff T is a subarray of B concatenated with itself (B+B)

        // We check all k possible shifts 's' (0 <= s < k)
        // Does T match B shifted left by 's'? i.e., T[i] == B[(i + s) % k]
        for (int s = 0; s < k; s++) {
            boolean match = true;
